label("$C$", C, NE);
label("$D$", D, SE);
pair E, F;
E = (4.5-.2,1-.2); F = (5, 3);
draw(A--E--D); draw(A--F--D);
label("$E$", E, N); label("$F$", F, NW);
dot(A);dot(B);dot(C);dot(D);dot(E);dot(F);
label("$x$", (1, 1.5), S); label("$x$", (2, 1), S+W); label("$x$", (2, -1), N+N+N+W);
label("$y$", (5.5+.3, .5-.3), S); label("$y$", (6.5+.3, 0)); label("$y$", (5+.5, -1.5+.3));
label("$110^{\circ}$",(2.5,3.5)); label("$100^{\circ}$",(6.5-.2,3.5));
pair P, Q, R, S;
P = (5.5, 3.5); Q = (5, 2.5); R = (4, 2); S = (3, 2);
draw(P--Q--R--S--cycle, dashed);
label("$x$", P--Q, E); label("$x$", Q--R, E); label("$x$", R--S, E);
label("$y$", P--S, N); label("$y$", Q--R, S);
[/asy]

Let $x$ denote the measure of one of the three trisecting angles at $\angle BAD$, and let $y$ denote the measure of one of the three trisecting angles at $\angle CDA$.  Then $\angle EAF = x$ and $\angle FAD = y$.  Since the sum of the measures of the angles in a triangle is $180^\circ$, we can find the measures of the other angles in $\triangle AFD$:
$$\angle ADF = 180^\circ - \frac{1}{3} \cdot 100^\circ - y = 180^\circ - \frac{100}{3}^\circ - y = \frac{470}{3}^\circ - y$$ $$\angle AFD = 180^\circ - x - \left( \frac{470}{3}^\circ - y \right) = \frac{110}{3}^\circ + y - x.$$Similarly, in $\triangle ABE$, we have $$\angle ABE = 180^\circ - \frac{1}{3} \cdot 110^\circ - x = 180^\circ - \frac{110}{3}^\circ - x = \frac{490}{3}^\circ - x,$$and $$\angle AEB = 180^\circ - \angle BAE - \angle ABE = 180^\circ - x - \left( \frac{490}{3}^\circ - x \right) = \frac{110}{3}^\circ.$$Finally, in quadrilateral $ABED$, we have $$\angle ADB = 360^\circ - \angle BAD - \angle ABE - \angle AEB = 360^\circ - 110^\circ - \left( \frac{490}{3}^\circ - x \right) - \frac{110}{3}^\circ = \frac{110}{3}^\circ + x.$$Then in $\triangle ADF$, we have $$\angle AFD = 180^\circ - \angle ADF - \angle ADB = 180^\circ - \left( \frac{470}{3}^\circ - y \right) - \left( \frac{110}{3}^\circ + x \right) = \boxed{60^\circ}.$$

