D = C + dir(90)*(A - C);
E = D + dir(90)*(C - D);
F = E + dir(90)*(D - E);
G = F + dir(90)*(E - F);

pair[] dots = {A, B, C, D, E, F, G};

draw(A--C--E--G--cycle);
draw(B--D--F--cycle);
draw(A--G);
draw(C--F);
draw(E--B);

label("$A_1$", A, A);
label("$A_2$", B, SW);
label("$A_3$", C, SE);
label("$A_4$", D, NE);
label("$A_5$", E, NW);
label("$A_6$", F, SW);
label("$A_7$", G, SE);

dot(dots);

draw(B--C--D--E--F--G--A--cycle);
draw(A--F);
draw(B--G);
draw(C--A);
draw(D--B);
draw(E--C);
draw(F--D);
draw(G--E);

label("$A$", A, A);
label("$B$", B, SW);
label("$C$", C, SE);
label("$D$", F, S);
label("$E$", E, NW);
label("$F$", F, SW);
